class Solution:
    def maxArrayValue(self, nums):
        def rec(arr):
            best = max(arr)
            for i in range(len(arr) - 1):
                if arr[i] <= arr[i + 1]:
                    new_arr = arr[:i] + (arr[i] + arr[i + 1],) + arr[i + 2:]
                    best = max(best, rec(new_arr))
            return best
        return rec(tuple(nums))

