class Solution:
    def maxArrayValue(self, nums):
        n = len(nums)
        merged = nums[-1]
        ans = merged
        for i in range(n - 2, -1, -1):
            if nums[i] <= merged:
                merged += nums[i]
            else:
                ans = max(ans, merged)
                merged = nums[i]
        ans = max(ans, merged)
        return ans

