var maxArrayValue = function(nums) {
    const n = nums.length;
    let merged = nums[n - 1];
    let ans = merged;
    for (let i = n - 2; i >= 0; i--) {
        if (nums[i] <= merged) {
            merged += nums[i];
        } else {
            ans = Math.max(ans, merged);
            merged = nums[i];
        }
    }
    ans = Math.max(ans, merged);
    return ans;
};
